// WF_CHANNEL_ANALYZE — Validate payload, auth check, INSERT pending row.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const payload = raw.body || raw;

const channelUrl = (payload.channel_url || '').trim();
let analysisGroupId = payload.analysis_group_id || null;

if (!channelUrl) {
  return [{ json: { success: false, error: 'channel_url is required', http_status: 400 } }];
}

// Generate analysis_group_id if not provided
if (!analysisGroupId) {
  analysisGroupId = crypto.randomUUID();
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// INSERT pending row into channel_analyses
try {
  const insertRes = await fetch(`${supabaseUrl}/rest/v1/channel_analyses`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify({
      youtube_channel_id: 'pending',
      channel_name: 'Resolving...',
      channel_url: channelUrl,
      analysis_group_id: analysisGroupId,
      status: 'pending'
    })
  });
  if (!insertRes.ok) {
    const errText = await insertRes.text();
    return [{ json: { success: false, error: `Insert failed: HTTP ${insertRes.status}: ${errText.slice(0, 200)}`, http_status: 500 } }];
  }
  const arr = await insertRes.json();
  const row = Array.isArray(arr) && arr[0] ? arr[0] : null;
  if (!row || !row.id) {
    return [{ json: { success: false, error: 'Insert returned empty body', http_status: 500 } }];
  }

  return [{ json: {
    success: true,
    analysis_id: row.id,
    analysis_group_id: analysisGroupId,
    channel_url: channelUrl,
    http_status: 202
  } }];
} catch (e) {
  return [{ json: { success: false, error: `Exception: ${e.message}`, http_status: 500 } }];
}

// Gate: only continue if the insert succeeded.
const data = $input.first().json;
if (!data.success) {
  return []; // empty = stop execution on this branch
}
return [{ json: data }];

// Resolve YouTube channel ID from URL or handle.
// Supports: @handle, /channel/UCXXX, /c/name, /@handle

const data = $input.first().json;
const channelUrl = data.channel_url;
const analysisId = data.analysis_id;
const ytKey = $env.YOUTUBE_API_KEY;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, status: 0, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

async function failAnalysis(msg) {
  await fetch(`${supabaseUrl}/rest/v1/channel_analyses?id=eq.${analysisId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'failed', error_message: msg })
  });
}

// Update status to analyzing
await fetch(`${supabaseUrl}/rest/v1/channel_analyses?id=eq.${analysisId}`, {
  method: 'PATCH',
  headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
  body: JSON.stringify({ status: 'analyzing' })
});

// Parse URL to extract handle or channel ID
let channelId = null;
let handle = null;

// Direct channel ID: /channel/UCXXX or bare UCXXX
const ucMatch = channelUrl.match(/\/channel\/(UC[\w-]+)/) || channelUrl.match(/^(UC[\w-]{20,})$/);
if (ucMatch) {
  channelId = ucMatch[1];
}

// Handle: @handle in URL or plain @handle
if (!channelId) {
  const handleMatch = channelUrl.match(/@([\w.-]+)/) || channelUrl.match(/\/c\/([\w.-]+)/);
  if (handleMatch) {
    handle = handleMatch[1];
  }
}

// If we have a handle, resolve via channels.list?forHandle
if (!channelId && handle) {
  const resolveUrl = `https://www.googleapis.com/youtube/v3/channels?part=id&forHandle=${encodeURIComponent(handle)}&key=${ytKey}`;
  const resolveRes = await fetchWithRetry(resolveUrl, { method: 'GET' }, 'yt_resolve_handle');
  if (resolveRes.quota) {
    await failAnalysis('YouTube API quota exhausted during handle resolution');
    return [{ json: { ...data, failed: true, error: 'quota_exhausted' } }];
  }
  if (resolveRes.ok) {
    const items = resolveRes.json?.items || [];
    if (items.length > 0) {
      channelId = items[0].id;
    }
  }
}

// Fallback: try search.list as last resort
if (!channelId) {
  const searchTerm = handle || channelUrl.replace(/https?:\/\//, '').replace(/www\.youtube\.com\//, '').replace(/\//g, '');
  const searchUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(searchTerm)}&type=channel&maxResults=1&key=${ytKey}`;
  const searchRes = await fetchWithRetry(searchUrl, { method: 'GET' }, 'yt_search_channel');
  if (searchRes.ok) {
    const items = searchRes.json?.items || [];
    if (items.length > 0) {
      channelId = items[0].snippet?.channelId || items[0].id?.channelId;
    }
  }
}

if (!channelId) {
  await failAnalysis(`Could not resolve YouTube channel from URL: ${channelUrl}`);
  return [{ json: { ...data, failed: true, error: 'channel_not_found' } }];
}

// Log resolution
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null,
      topic_id: null,
      stage: 'channel_analyze',
      scene_number: null,
      action: 'resolve_channel',
      status: 'success',
      duration_ms: 0,
      cost_usd: 0,
      retry_count: 0
    })
  });
} catch (_) {}

return [{ json: { ...data, youtube_channel_id: channelId, handle: handle || null, failed: false } }];

// Fetch full channel metadata: snippet, statistics, contentDetails, brandingSettings.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const channelId = data.youtube_channel_id;
const analysisId = data.analysis_id;
const ytKey = $env.YOUTUBE_API_KEY;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, status: 0, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

async function failAnalysis(msg) {
  await fetch(`${supabaseUrl}/rest/v1/channel_analyses?id=eq.${analysisId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'failed', error_message: msg })
  });
}

const metaStart = Date.now();
const metaUrl = `https://www.googleapis.com/youtube/v3/channels?part=snippet,statistics,contentDetails,brandingSettings&id=${channelId}&key=${ytKey}`;
const metaRes = await fetchWithRetry(metaUrl, { method: 'GET' }, 'yt_channel_metadata');

if (metaRes.quota) {
  await failAnalysis('YouTube API quota exhausted during metadata fetch');
  return [{ json: { ...data, failed: true, error: 'quota_exhausted' } }];
}
if (!metaRes.ok || !metaRes.json?.items?.length) {
  await failAnalysis(`Channel metadata fetch failed: ${metaRes.error || 'no items returned'}`);
  return [{ json: { ...data, failed: true, error: 'metadata_fetch_failed' } }];
}

const ch = metaRes.json.items[0];
const snippet = ch.snippet || {};
const stats = ch.statistics || {};
const content = ch.contentDetails || {};
const branding = ch.brandingSettings || {};

const channelMeta = {
  channel_name: snippet.title || 'Unknown',
  channel_description: (snippet.description || '').slice(0, 5000),
  channel_avatar_url: snippet.thumbnails?.high?.url || snippet.thumbnails?.medium?.url || null,
  channel_banner_url: branding.image?.bannerExternalUrl || null,
  country: snippet.country || null,
  custom_url: snippet.customUrl || null,
  channel_created_at: snippet.publishedAt || null,
  subscriber_count: parseInt(stats.subscriberCount || '0', 10),
  total_view_count: parseInt(stats.viewCount || '0', 10),
  video_count: parseInt(stats.videoCount || '0', 10),
  uploads_playlist_id: content.relatedPlaylists?.uploads || null
};

// Log
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null, topic_id: null, stage: 'channel_analyze',
      scene_number: null, action: 'fetch_channel_metadata', status: 'success',
      duration_ms: Date.now() - metaStart, cost_usd: 0, retry_count: (metaRes.attempts || 1) - 1
    })
  });
} catch (_) {}

return [{ json: { ...data, channel_meta: channelMeta, failed: false } }];

// Fetch uploads playlist (50 videos), get stats, rank top 20, calculate metrics.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const channelId = data.youtube_channel_id;
const analysisId = data.analysis_id;
const uploadsPlaylist = data.channel_meta.uploads_playlist_id;
const ytKey = $env.YOUTUBE_API_KEY;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, status: 0, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

async function failAnalysis(msg) {
  await fetch(`${supabaseUrl}/rest/v1/channel_analyses?id=eq.${analysisId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'failed', error_message: msg })
  });
}

function parseIsoDuration(s) {
  if (!s || typeof s !== 'string') return 0;
  const m = s.match(/^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/);
  if (!m) return 0;
  return parseInt(m[1] || '0', 10) * 3600 + parseInt(m[2] || '0', 10) * 60 + parseInt(m[3] || '0', 10);
}

function median(arr) {
  if (!arr.length) return 0;
  const s = [...arr].sort((a, b) => a - b);
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : Math.round((s[m - 1] + s[m]) / 2);
}

if (!uploadsPlaylist) {
  await failAnalysis('No uploads playlist found for channel');
  return [{ json: { ...data, failed: true, error: 'no_uploads_playlist' } }];
}

const videosStart = Date.now();

// Fetch up to 50 video IDs from uploads playlist
let allVideoIds = [];
let nextPageToken = null;

for (let page = 0; page < 2; page++) {
  let plUrl = `https://www.googleapis.com/youtube/v3/playlistItems?part=contentDetails&playlistId=${uploadsPlaylist}&maxResults=50&key=${ytKey}`;
  if (nextPageToken) plUrl += `&pageToken=${nextPageToken}`;

  const plRes = await fetchWithRetry(plUrl, { method: 'GET' }, 'yt_playlist_items');
  if (plRes.quota) {
    await failAnalysis('YouTube API quota exhausted during video fetch');
    return [{ json: { ...data, failed: true, error: 'quota_exhausted' } }];
  }
  if (!plRes.ok) break;

  const items = plRes.json?.items || [];
  allVideoIds.push(...items.map(i => i.contentDetails?.videoId).filter(Boolean));
  nextPageToken = plRes.json?.nextPageToken;
  if (!nextPageToken || allVideoIds.length >= 50) break;
}

allVideoIds = allVideoIds.slice(0, 50);

if (allVideoIds.length === 0) {
  await failAnalysis('No videos found in uploads playlist');
  return [{ json: { ...data, failed: true, error: 'no_videos' } }];
}

// Fetch video stats in batches of 50
let allVideos = [];
for (let i = 0; i < allVideoIds.length; i += 50) {
  const batch = allVideoIds.slice(i, i + 50);
  const vUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet,contentDetails&id=${batch.join(',')}&key=${ytKey}`;
  const vRes = await fetchWithRetry(vUrl, { method: 'GET' }, 'yt_video_stats');
  if (vRes.quota) {
    await failAnalysis('YouTube API quota exhausted during video stats fetch');
    return [{ json: { ...data, failed: true, error: 'quota_exhausted' } }];
  }
  if (vRes.ok) allVideos.push(...(vRes.json?.items || []));
}

// Parse all videos
const parsed = allVideos.map(v => {
  const views = parseInt(v.statistics?.viewCount || '0', 10);
  const likes = parseInt(v.statistics?.likeCount || '0', 10);
  const comments = parseInt(v.statistics?.commentCount || '0', 10);
  const durationSec = parseIsoDuration(v.contentDetails?.duration);
  return {
    video_id: v.id,
    title: (v.snippet?.title || '').slice(0, 300),
    published_at: v.snippet?.publishedAt || null,
    thumbnail_url: v.snippet?.thumbnails?.high?.url || v.snippet?.thumbnails?.medium?.url || null,
    views, likes, comments,
    duration_seconds: durationSec,
    is_shorts: durationSec > 0 && durationSec <= 60
  };
});

// Filter to long-form (>60s) for analysis, keep shorts separate
const longForm = parsed.filter(v => !v.is_shorts);
const shorts = parsed.filter(v => v.is_shorts);

const viewsArr = longForm.map(v => v.views);
const avgViews = viewsArr.length ? Math.round(viewsArr.reduce((a, b) => a + b, 0) / viewsArr.length) : 0;
const medianViews = median(viewsArr);

// Top 20 by views (long-form)
const top20 = [...longForm].sort((a, b) => b.views - a.views).slice(0, 20);

// Calculate outlier_score for each top video
const denominator = medianViews || 1;
top20.forEach(v => {
  v.outlier_score = Math.round((v.views / denominator) * 100) / 100;
});

// Upload frequency: days between uploads (long-form only)
const pubDates = longForm
  .map(v => v.published_at ? new Date(v.published_at).getTime() : 0)
  .filter(t => t > 0)
  .sort((a, b) => b - a);

let uploadFreqDays = null;
if (pubDates.length >= 2) {
  const gaps = [];
  for (let i = 0; i < pubDates.length - 1; i++) {
    gaps.push((pubDates[i] - pubDates[i + 1]) / 86400000);
  }
  uploadFreqDays = Math.round(median(gaps) * 10) / 10;
}

// Average video duration (long-form)
const avgDurationSec = longForm.length
  ? Math.round(longForm.reduce((s, v) => s + v.duration_seconds, 0) / longForm.length)
  : 0;

// Growth trajectory: compare avg views of newest 10 vs oldest 10
const byDate = [...longForm].sort((a, b) => {
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return db - da;
});
const newest10 = byDate.slice(0, Math.min(10, byDate.length));
const oldest10 = byDate.slice(Math.max(0, byDate.length - 10));
const newestAvg = newest10.length ? newest10.reduce((s, v) => s + v.views, 0) / newest10.length : 0;
const oldestAvg = oldest10.length ? oldest10.reduce((s, v) => s + v.views, 0) / oldest10.length : 0;

let growthTrajectory = 'stable';
if (oldestAvg > 0) {
  const ratio = newestAvg / oldestAvg;
  if (ratio > 1.5) growthTrajectory = 'accelerating';
  else if (ratio < 0.5) growthTrajectory = 'decelerating';
  else if (longForm.length < 5 && pubDates.length >= 2 && (Date.now() - pubDates[0]) > 90 * 86400000) growthTrajectory = 'dormant';
}

// Estimated monthly views
const totalViews = data.channel_meta.total_view_count || 0;
const channelAgeDays = data.channel_meta.channel_created_at
  ? Math.max(1, (Date.now() - new Date(data.channel_meta.channel_created_at).getTime()) / 86400000)
  : 365;
const estimatedMonthlyViews = Math.round(totalViews / (channelAgeDays / 30));

// All 50 titles for Claude
const allTitles = parsed.map(v => v.title);

// Log
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null, topic_id: null, stage: 'channel_analyze',
      scene_number: null, action: 'fetch_videos', status: 'success',
      duration_ms: Date.now() - videosStart, cost_usd: 0, retry_count: 0
    })
  });
} catch (_) {}

return [{ json: {
  ...data,
  top_videos: top20,
  all_titles: allTitles,
  all_videos_count: parsed.length,
  long_form_count: longForm.length,
  shorts_count: shorts.length,
  metrics: {
    avg_views_per_video: avgViews,
    median_views_per_video: medianViews,
    upload_frequency_days: uploadFreqDays,
    avg_video_duration_seconds: avgDurationSec,
    estimated_monthly_views: estimatedMonthlyViews,
    growth_trajectory: growthTrajectory
  },
  failed: false
} }];

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const analysisId = data.analysis_id;
const anthropicKey = $env.ANTHROPIC_API_KEY;
const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json'
};

const sleep = function(ms) { return new Promise(function(r) { setTimeout(r, ms); }); };

async function failAnalysis(msg) {
  await fetch(supabaseUrl + '/rest/v1/channel_analyses?id=eq.' + analysisId, {
    method: 'PATCH',
    headers: Object.assign({}, sbHeaders, { 'Prefer': 'return=minimal' }),
    body: JSON.stringify({ status: 'failed', error_message: msg })
  });
}

const meta = data.channel_meta;
const metrics = data.metrics;
const top20 = data.top_videos || [];
const allTitles = data.all_titles || [];

var top20Lines = [];
for (var i = 0; i < top20.length; i++) {
  var v = top20[i];
  top20Lines.push((i + 1) + '. "' + v.title + '" - ' + v.views + ' views, ' + v.likes + ' likes, ' + v.comments + ' comments, ' + Math.round(v.duration_seconds / 60) + 'min, outlier: ' + v.outlier_score + 'x median');
}
var top20Block = top20Lines.join('\n');

var titleLines = [];
for (var ti = 0; ti < allTitles.length; ti++) {
  titleLines.push((ti + 1) + '. ' + allTitles[ti]);
}
var allTitlesBlock = titleLines.join('\n');

var systemPrompt = 'You are an elite YouTube channel strategist and competitive intelligence analyst.\n\n'
  + 'CORE RULES:\n'
  + '1. Every claim you make MUST cite specific evidence from the data provided. When you say "this channel is strong at X," reference the specific video(s) or metric(s) that prove it. No unsupported assertions.\n'
  + '2. You can ONLY analyze what is in the data. Do not infer revenue, CTR, audience retention, or any metric not explicitly provided. If you need data you do not have, say "insufficient data" for that field.\n'
  + '3. Thumbnail analysis is INFERENCE ONLY based on content type, titles, and niche conventions. You have not seen the actual thumbnails. Label this section clearly as inferred.\n'
  + '4. Scores must follow the rubric provided. Do not inflate or deflate. A score of 80+ should be rare and reserved for genuinely exceptional signals.\n'
  + '5. Blue-ocean opportunities must be SPECIFIC and ACTIONABLE - not "make better content" but "cover [specific topic] from [specific angle] because [specific evidence from the data]."\n'
  + '6. Return ONLY valid JSON. No markdown, no backticks wrapping the JSON, no commentary before or after. The first character of your response must be {.';

var userPrompt = 'Analyze this YouTube channel in depth. Ground every finding in the data below.\n\n'
  + 'CHANNEL INFO:\n'
  + '- Name: ' + (meta.channel_name || '') + '\n'
  + '- Description: ' + ((meta.channel_description || '').slice(0, 1500)) + '\n'
  + '- Country: ' + (meta.country || 'Unknown') + '\n'
  + '- Created: ' + (meta.channel_created_at || 'Unknown') + '\n'
  + '- Subscribers: ' + (meta.subscriber_count || 0) + '\n'
  + '- Total views: ' + (meta.total_view_count || 0) + '\n'
  + '- Video count: ' + (meta.video_count || 0) + '\n\n'
  + 'METRICS:\n'
  + '- Avg views/video: ' + (metrics.avg_views_per_video || 0) + '\n'
  + '- Median views/video: ' + (metrics.median_views_per_video || 0) + '\n'
  + '- Upload frequency: every ' + (metrics.upload_frequency_days || '?') + ' days\n'
  + '- Avg video duration: ' + Math.round((metrics.avg_video_duration_seconds || 0) / 60) + ' minutes\n'
  + '- Growth trajectory: ' + (metrics.growth_trajectory || 'stable') + '\n'
  + '- Est. monthly views: ' + (metrics.estimated_monthly_views || 0) + '\n\n'
  + 'TOP 20 VIDEOS BY VIEWS:\n'
  + top20Block + '\n\n'
  + 'ALL ' + allTitles.length + ' RECENT VIDEO TITLES:\n'
  + allTitlesBlock + '\n\n'
  + 'ANALYSIS INSTRUCTIONS:\n\n'
  + 'For primary_topics: Cluster the video titles into 5-10 distinct topic groups. Name each group specifically (not "general finance" but "credit card annual fee comparisons").\n\n'
