async function fetchRetry(url, opts, retries) {
  if (!retries) retries = 3;
  for (let i = 0; i < retries; i++) {
    try {
      const r = await fetch(url, opts);
      if (r.ok) return r;
      if (r.status === 403) return { ok: false, status: 403, statusText: 'Forbidden' };
      if (r.status >= 400 && r.status < 500) return { ok: false, status: r.status, statusText: await r.text() };
    } catch (e) { if (i === retries - 1) throw e; }
    await new Promise(function(res) { setTimeout(res, 1000 * Math.pow(2, i)); });
  }
  return null;
}

